<template>
	<u-list @scrolltolower="onScrollToLower" v-if="displayList.length" :height="height">
		<u-list-item v-for="(item, index) in displayList" :key="getKey(item, index)">
			<slot :item="item" :index="index">
				<view class="cs-item" @click="$emit('item-click', item, index)">
					<view>{{ item  }}</view>
				</view>
			</slot>
		</u-list-item>

		<!-- 加载更多/没有更多 -->
		<u-loadmore v-if="displayList.length === totalCount && !loading" status="nomore" />
		<u-loadmore v-if="loading" status="loading" />
	</u-list>

	<!--无数据插槽 -->
	<view v-else-if="$slots.empty">
		<slot name="empty" />
	</view>
	<view v-else-if="!displayList.length" class="cs-empty">暂无数据</view>
</template>

<script>
	export default {
		name: 'CommonScroll',
		props: {
			// 必传数据,总列表数据
			items: {
				type: Array,
				default: () => [],
			},
			// 每次添加的数据量
			pageSize: {
				type: Number,
				default: 5,
			},
			// U-list高度
			height: {
				type: String,
				default: '100%',
			},
			// id 如:petId
			keyField: {
				type: String,
				default: '',
			},
			// 初始化
			autoInit: {
				type: Boolean,
				default: true,
			},
		},
		data() {
			return {
				displayList: [],
				loading: false,
				currentLength: 0,
			};
		},
		computed: {
			totalCount() {
				return this.items ? this.items.length : 0;
			},
			hasMore() {
				return this.currentLength < this.totalCount;
			},
		},
		watch: {
			items: {
				handler() {
					if (this.autoInit) {
						this.reset();
					} else {
						// 如果不自动初始化，仅更新总数但保留显示列表
					}
				},
				deep: true,
				immediate: true,
			},
		},
		mounted() {
			if (this.autoInit) {
				this.initLoad();
			}
		},
		methods: {
			getKey(item, index) {
				//检查当前数据项 item 是否包含 keyField 
				if (this.keyField && item && Object.prototype.hasOwnProperty.call(item, this.keyField)) {
					return item[this.keyField];
				}
				return `${index}-${this._uid}`;
			},

			initLoad() {
				console.log(this.items);
				this.displayList = [];
				this.currentLength = 0;
				this.loadMoreData();
			},

			// 加载下一页
			loadMoreData() {
				if (this.loading) return;
				if (!this.hasMore && this.currentLength > 0) return;

				this.loading = true;
				//获取截取数据的start和end
				const start = this.currentLength;
				let end = start + (this.pageSize > 0 ? this.pageSize : this.totalCount);
				if (end > this.totalCount) end = this.totalCount;

				const newData = this.items.slice(start, end);
				// 添加数据
				this.displayList = this.displayList.concat(newData);
				this.currentLength = this.displayList.length;

				//可在父组件接受改组件信息
				this.$emit('load', {
					added: newData,
					displayList: this.displayList,
					currentLength: this.currentLength,
					hasMore: this.hasMore,
				});

				this.loading = false;
			},

			//向下滑动时触发的方法
			onScrollToLower() {
				if (this.loading || !this.hasMore) return;
				this.$emit('scrolltolower');
				this.loadMoreData();
			},

			//刷新
			reset(reinit = true) {
				this.displayList = [];
				this.currentLength = 0;
				this.loading = false;
				if (reinit) this.initLoad();
			},

			//外部可调用的刷新
			refresh() {
				this.reset(true);
			},

			setItems(newItems = []) {
				//如果父组件传递了items属性，更新
				this.$emit('update:items', newItems);
			},
		},
	};
</script>

<style scoped lang="scss">
	.cs-item {
		padding: 12px;
	}

	.cs-empty {
		padding: 20px;
		text-align: center;
		color: #999;
	}
</style>